```javascript
function solve(nums, k) {
    nums.sort((a, b) => a - b);
    let max_size = 1;
    const n = nums.length;
    for (let left = 0; left < n; left++) {
        const target = nums[left] * k;
        let low = left;
        let high = n - 1;
        let right = left - 1;
        while (low <= high) {
            const mid = Math.floor((low + high) / 2);
            if (nums[mid] <= target) {
                right = mid;
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }
        const current_size = right - left + 1;
        if (current_size > max_size) {
            max_size = current_size;
        }
    }
    return n - max_size;
}
